public async IAsyncEnumerable<OrderDto> GetAllAsync(
    [EnumeratorCancellation] CancellationToken ct)
{
    await foreach (var order in _db.Orders.AsAsyncEnumerable().WithCancellation(ct))
        yield return new OrderDto(order.Id, order.Status, order.Total);
}

// Server-Sent Events (.NET 9) — AI streaming, progress updates
app.MapGet("/api/ai/stream", async (string prompt, AiService ai, CancellationToken ct) =>
{
    var stream = ai.StreamCompletionAsync(prompt, ct);
    return TypedResults.ServerSentEvents(
        GetSseEvents(stream, ct),
        eventType: "token");
});

static async IAsyncEnumerable<SseItem<string>> GetSseEvents(
    IAsyncEnumerable<string> tokens,
    [EnumeratorCancellation] CancellationToken ct)
{
    await foreach (var token in tokens.WithCancellation(ct))
        yield return new SseItem<string>(token);
    yield return new SseItem<string>("[DONE]", eventType: "done");
}

